        "id": "2015_palmieri_distance_metric_learning_for",
        "label": "Palmieri et al. 2015",
        "title": "Distance Metric Learning for RRT-Based Motion Planning with Constant-Time Inference",
        "authors": [
          "Palmieri",
          "Arras"
        ],
